import{_ as t,W as n,X as o,Y as _,Z as e}from"./framework-91490e6a.js";const s={},c=e("p",null,"入职体检时有发现我的智齿蛀了，再加上近期开合口腔时感觉也有点痛。于是，作为不调休的人，我在今日前往了徐汇牙防所。",-1),l=e("p",null,"历经了四十分钟的等号，我终于被叫号，但是又被告知需要先去拍个全景片。于是我上楼拍片，拍完再下来告知医生我已经拍完，等待第二次叫号。",-1),r=e("p",null,"听闻这里拔智齿是一点都不疼。事实如此。经过了几处麻药注射，我的右侧口腔已经毫无感觉。当他伸进器材拔牙时，我毫无感觉，几分钟内就拔完了智齿。他让我咬住止血棉球，我试图做咬合的动作，但是毫无实感——我麻了，完全不知道我是否有进行咬合。但通过医生的反应来判断，应该是咬合了。",-1),a=e("p",null,"回家经过了两小时，口腔右侧还是麻的，毫无感觉，但是需要进食了，于是我听从有经验者的建议，决定喝流食——皮蛋瘦肉粥。用餐体验是：被打麻药的一侧毫无感觉，不知道吃的是啥，但是用另一侧就能体会到正常的味道。想必近期我应该都是用另一侧喝流食了吧。虽然只用一侧吃很不习惯。",-1),i=e("p",null,"大概过了三个小时，痛意向睡梦中的我袭来——麻药退了。群友的建议是冰敷，然而我并没有冰袋，于是我打开盒马下单了一箱罐装无糖可乐。",-1),d=e("p",null,"或许是十天的假期太让人劳累了，当晚我猛睡了10.5h。当我醒来的时候，拔牙处已经不痛了。似乎也可以不用再吃流食了——可以咀嚼了，而且即使在拔牙附近咀嚼也没事。于是就此告一段落吧。",-1);function h(u,p){return n(),o("div",null,[c,_(" more "),l,r,a,i,d])}const f=t(s,[["render",h],["__file","Extracting_Teeth.html.vue"]]);export{f as default};
